custom_css:
[selector='modal-style'] button:before {
    font-family: "Font Awesome 5 Free";
    content: "\f06e";
    display: inline-block;
    padding-right: 3px;
    vertical-align: middle;
    font-weight: 900;
}

[selector='modal-style'] button{
    color: #363638;
    border-color: #363638;
    background-color: white;
}

[selector='modal-style'] button:active{
    color: #fff;
    background-color: #363638;
    border-color: #363638;
}
